enum Message {
    Quit,
    Move { x: i32, y: i32 },
    Write(String),
}

fn process(msg: Message) {
    match msg {
        Message::Quit => println!("Quitting"),
        Message::Move { x, y } => println!("Move to {}, {}", x, y),
        Message::Write(s) => println!("Message: {}", s),
    }
}

